create table "_Tag"
(
    "Id"   bigint generated by default as identity
        constraint "_Tag_pk"
            primary key,
    "Type" text not null,
    "Name" text not null
);

alter table "_Tag"
    owner to bcrpro;

create index "_Tag_Name_index"
    on "_Tag" ("Name");

create index "_Tag_Type_index"
    on "_Tag" ("Type");

